// 1. Parsear respuesta de la IA
const respuesta = $input.first().json;
const texto = respuesta.content[0].text;
const ia = JSON.parse(texto.replace(/```json|```/g, '').trim());

// 2. Datos originales enviados por el ciudadano
const datos = $('Webhook').first().json.body;

// 3. Reglas de negocio DETERMINISTAS (la IA clasifica, las reglas ponen el precio)
const TARIFAS = { colchon: 35000, mueble: 45000, electrodomestico: 50000, escombros: 60000, otro: 40000 };
const SUBSIDIOS = { 1: 70, 2: 50, 3: 30, 4: 10, 5: 0, 6: 0 }; // % de subsidio por estrato

let tarifa_base = 0, subsidio_pct = 0, precio_final = 0;
if (ia.es_residuo_voluminoso) {
  tarifa_base = TARIFAS[ia.tipo] ?? TARIFAS.otro;
  if (ia.peso_kg > 50) tarifa_base += 20000; // recargo por peso
  subsidio_pct = SUBSIDIOS[datos.estrato] ?? 0;
  precio_final = Math.round(tarifa_base * (1 - subsidio_pct / 100));
}

return [{ json: {
  es_valido: ia.es_residuo_voluminoso === true,
  motivo_rechazo: ia.motivo_rechazo ?? null,
  tipo: ia.tipo ?? null,
  descripcion: ia.descripcion ?? null,
  peso_kg: ia.peso_kg ?? null,
  volumen_m3: ia.volumen_m3 ?? null,
  tarifa_base, subsidio_pct, precio_final,
  estrato: Number(datos.estrato),
  lat: Number(datos.lat),
  lng: Number(datos.lng),
  direccion: datos.direccion ?? null,
  estado: 'pendiente',
  foto_base64: datos.foto_base64
}}];
